// // This module implements a 12-bit register with an asynchronous reset signal and an active-high enable signal. When the enable signal is high, the data input is loaded into the register.
module register (
	input clk,
	input reset,
	input enable_n,
	input [11:0] data_in,
	output reg [11:0] data_out
);always @(posedge clk or posedge reset) begin
	if (reset)
		data_out <= 12'b000000000000;
	else if (~enable_n)
		data_out <= data_in;
end

endmodule
